mapper.select:
SELECT id, user_id, departure_airport_code, arrival_airport_code, behavior_type, flight_number, created_at
FROM user_flight_history
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, user_id, departure_airport_code, arrival_airport_code, behavior_type, flight_number, created_at
FROM user_flight_history
WHERE user_id = #{userId} AND behavior_type = #{behaviorType}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT departure_airport_code || '-' || arrival_airport_code AS route
FROM user_flight_history
WHERE user_id = #{userId}
GROUP BY departure_airport_code, arrival_airport_code
ORDER BY COUNT(*) DESC
LIMIT #{limit}
